module RefModule(clk, rst, data, q);

    input  clk;
    input  rst;
    input  data;
    output reg [7:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 8'b00000000;
        else
            q <= {q[6:0], data};
    end

endmodule
